#include <stdio.h>
#include <stdlib.h>
#include <pthread.h>
#include <stdint.h>
#include <string.h>
#include <time.h>

#define NUM_THREADS 4
#define ITERATIONS 10000000

// Without padding - variables share a cache line (FALSE SHARING)
struct NoPadding {
 volatile long counter1; // Used by thread 1
 volatile long counter2; // Used by thread 2
 volatile long counter3; // Used by thread 3
 volatile long counter4; // Used by thread 4
};

// With padding - each variable on separate cache line
// Assuming 64-byte cache line, we pad to ensure separation
struct WithPadding {
 volatile long counter1; // Used by thread 1
 char pad1[64 - sizeof(long)]; // Padding to next cache line
 volatile long counter2; // Used by thread 2
 char pad2[64 - sizeof(long)];
 volatile long counter3; // Used by thread 3
 char pad3[64 - sizeof(long)];
 volatile long counter4; // Used by thread 4
 char pad4[64 - sizeof(long)];
};

// Alternative: Use array with cache line size alignment
#define CACHE_LINE_SIZE 64
#define ALIGNED __attribute__((aligned(CACHE_LINE_SIZE)))

struct AlignedData {
 volatile long counter[NUM_THREADS];
};

// Without padding version
struct NoPadding shared_no_pad;

// With padding version
struct WithPadding shared_with_pad;

// Array version (each element aligned to cache line)
struct AlignedData ALIGNED shared_aligned[NUM_THREADS];

void* increment_counter_no_pad(void* arg) {
 int thread_id = *(int*)arg;
 for (int i = 0; i < ITERATIONS; i++) {
 if (thread_id == 0) shared_no_pad.counter1++;
 else if (thread_id == 1) shared_no_pad.counter2++;
 else if (thread_id == 2) shared_no_pad.counter3++;
 else shared_no_pad.counter4++;
 }
 return NULL;
}

void* increment_counter_with_pad(void* arg) {
 int thread_id = *(int*)arg;
 for (int i = 0; i < ITERATIONS; i++) {
 if (thread_id == 0) shared_with_pad.counter1++;
 else if (thread_id == 1) shared_with_pad.counter2++;
 else if (thread_id == 2) shared_with_pad.counter3++;
 else shared_with_pad.counter4++;
 }
 return NULL;
}

void* increment_counter_aligned(void* arg) {
 int thread_id = *(int*)arg;
 for (int i = 0; i < ITERATIONS; i++) {
 shared_aligned[thread_id].counter[0]++;
 }
 return NULL;
}

double run_test(void* (*worker)(void*), int* thread_ids) {
 pthread_t threads[NUM_THREADS];

 struct timespec start, end;
 clock_gettime(CLOCK_MONOTONIC, &start);

 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_create(&threads[i], NULL, worker, &thread_ids[i]);
 }

 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(threads[i], NULL);
 }

 clock_gettime(CLOCK_MONOTONIC, &end);

 return (end.tv_sec - start.tv_sec) + 
 (end.tv_nsec - start.tv_nsec) / 1e9;
}

int main() {
 int thread_ids[NUM_THREADS] = {0, 1, 2, 3};

 printf("=================================================\n");
 printf("FALSE SHARING DEMONSTRATION\n");
 printf("Cache Line Size: %d bytes\n", CACHE_LINE_SIZE);
 printf("Threads: %d, Iterations per thread: %d\n", 
 NUM_THREADS, ITERATIONS);
 printf("=================================================\n\n");

 // Test 1: Without padding (False Sharing)
 memset(&shared_no_pad, 0, sizeof(shared_no_pad));
 double time_no_pad = run_test(increment_counter_no_pad, thread_ids);
 printf("WITHOUT PADDING (False Sharing):\n");
 printf(" Time: %.4f seconds\n", time_no_pad);
 printf(" Total increments: %ld\n\n", 
 shared_no_pad.counter1 + shared_no_pad.counter2 + 
 shared_no_pad.counter3 + shared_no_pad.counter4);

 // Test 2: With padding (No False Sharing)
 memset(&shared_with_pad, 0, sizeof(shared_with_pad));
 double time_with_pad = run_test(increment_counter_with_pad, thread_ids);
 printf("WITH PADDING (No False Sharing):\n");
 printf(" Time: %.4f seconds\n", time_with_pad);
 printf(" Total increments: %ld\n\n", 
 shared_with_pad.counter1 + shared_with_pad.counter2 + 
 shared_with_pad.counter3 + shared_with_pad.counter4);

 // Test 3: Array with alignment
 memset(shared_aligned, 0, sizeof(shared_aligned));
 double time_aligned = run_test(increment_counter_aligned, thread_ids);
 printf("WITH ALIGNED ARRAYS (No False Sharing):\n");
 printf(" Time: %.4f seconds\n", time_aligned);
 long total = 0;
 for (int i = 0; i < NUM_THREADS; i++) {
 total += shared_aligned[i].counter[0];
 }
 printf(" Total increments: %ld\n\n", total);

 // Summary
 printf("=================================================\n");
 printf("PERFORMANCE COMPARISON:\n");
 printf(" No padding time: %.4f s (baseline)\n", time_no_pad);
 printf(" With padding time: %.4f s\n", time_with_pad);
 printf(" Aligned array time: %.4f s\n", time_aligned);

 if (time_with_pad < time_no_pad) {
 double speedup = time_no_pad / time_with_pad;
 printf("\n Speedup with padding: %.2fx\n", speedup);
 printf(" This demonstrates FALSE SHARING overhead!\n");
 }
 printf("=================================================\n");

 return 0;
}
